package io.github.mamedovilkin.weather.network.repository

import io.ktor.client.HttpClient
import io.ktor.client.engine.mock.MockEngine
import io.ktor.client.engine.mock.respond
import io.ktor.client.plugins.contentnegotiation.ContentNegotiation
import io.ktor.client.plugins.logging.Logger
import io.ktor.client.plugins.logging.Logging
import io.ktor.client.plugins.logging.SIMPLE
import io.ktor.http.HttpHeaders
import io.ktor.http.HttpStatusCode
import io.ktor.http.headersOf
import io.ktor.serialization.kotlinx.json.json
import kotlinx.serialization.json.Json

private fun httpClient(mockEngine: MockEngine): HttpClient {
    return HttpClient(mockEngine) {
        install(Logging) { logger = Logger.SIMPLE }

        install(ContentNegotiation) {
            json(Json{
                ignoreUnknownKeys = true
            })
        }
    }
}

private fun successMockResponse(content: String): MockEngine {
    return MockEngine {
        respond(
            content = content,
            status = HttpStatusCode.OK,
            headers = headersOf(HttpHeaders.ContentType, "application/json")
        )
    }
}

fun getFailureHttpClient(): HttpClient {
    val mockEngine = MockEngine {
        respond(
            content = "Bad gateway",
            status = HttpStatusCode.BadGateway,
            headers = headersOf(HttpHeaders.ContentType, "text/plain")
        )
    }

    return httpClient(mockEngine)
}

fun getSuccessHttpClientWeather(): HttpClient {
    return httpClient(successMockResponse("{\"coord\":{\"lon\":50,\"lat\":50},\"weather\":[{\"id\":804,\"main\":\"Clouds\",\"description\":\"overcast clouds\",\"icon\":\"04d\"}],\"base\":\"stations\",\"main\":{\"temp\":16.96,\"feels_like\":16.49,\"temp_min\":16.96,\"temp_max\":16.96,\"pressure\":1010,\"humidity\":68,\"sea_level\":1010,\"grnd_level\":1009},\"visibility\":10000,\"wind\":{\"speed\":3.12,\"deg\":29,\"gust\":3.75},\"clouds\":{\"all\":100},\"dt\":1747064939,\"sys\":{\"country\":\"KZ\",\"sunrise\":1747011510,\"sunset\":1747066459},\"timezone\":18000,\"id\":607847,\"name\":\"West Kazakhstan\",\"cod\":200}"))
}

